import React, { useEffect } from 'react';
import { useParams } from 'react-router-dom';
import BlogPostBody from '../components/BlogPost';
import {
  HeaderBar,
  HeaderInner,
  Brand,
  NavRow,
  NavA,
  PostContainer,
  PostInner,
  BackLink,
  PostCover,
  PostTitle,
  PostSubtitle,
  PostMeta,
  TagRow,
  Tag,
  FooterBar,
  FooterInner,
  FooterLinks,
  FootRights,
  NotFoundWrap,
} from '../components/BlogPost/BlogPostElements';
import { getPostBySlug } from '../data/blogPosts';

const formatDate = (iso) =>
  new Date(`${iso}T00:00:00`).toLocaleDateString('en-US', {
    year: 'numeric',
    month: 'long',
    day: 'numeric',
  });

const BlogHeader = () => (
  <HeaderBar>
    <HeaderInner>
      <Brand to="/">
        <span>::</span>
        <b>RM</b>
        <span>::</span>
      </Brand>
      <NavRow>
        <NavA href="/#work">Projects</NavA>
        <NavA className="hidem" href="/#writing">
          Writing
        </NavA>
        <NavA href="/#contact">Contact</NavA>
      </NavRow>
    </HeaderInner>
  </HeaderBar>
);

const BlogFooter = () => (
  <FooterBar>
    <FooterInner>
      <FooterLinks>
        <a href="/">Home</a>
        <a href="/#work">Projects</a>
        <a href="/#writing">Writing</a>
        <a href="/#contact">Contact</a>
        <a
          href="https://github.com/Ryan-McCauley"
          target="_blank"
          rel="noreferrer"
        >
          GitHub
        </a>
      </FooterLinks>
      <FootRights>© Ryan McCauley {new Date().getFullYear()}</FootRights>
    </FooterInner>
  </FooterBar>
);

const BlogPostPage = () => {
  const { slug } = useParams();
  const post = getPostBySlug(slug);

  useEffect(() => {
    window.scrollTo(0, 0);
  }, [slug]);

  if (!post) {
    return (
      <>
        <BlogHeader />
        <NotFoundWrap>
          <h1>Post not found</h1>
          <BackLink href="/#writing">&larr; Back to all posts</BackLink>
        </NotFoundWrap>
        <BlogFooter />
      </>
    );
  }

  return (
    <>
      <BlogHeader />
      <PostContainer>
        <PostInner>
          <BackLink href="/#writing">&larr; Back to all posts</BackLink>
          <PostCover src={post.cover} alt={post.title} />
          <PostTitle>{post.title}</PostTitle>
          <PostSubtitle>{post.subtitle}</PostSubtitle>
          <PostMeta>
            <span>{formatDate(post.date)}</span>
            <span>·</span>
            <span>{post.readingTime}</span>
            <TagRow>
              {post.tags.map((tag) => (
                <Tag key={tag}>{tag}</Tag>
              ))}
            </TagRow>
          </PostMeta>
          <BlogPostBody blocks={post.blocks} />
          <BackLink href="/#writing" style={{ marginTop: '48px' }}>
            &larr; Back to all posts
          </BackLink>
        </PostInner>
      </PostContainer>
      <BlogFooter />
    </>
  );
};

export default BlogPostPage;
