const STRANGE_WORDS = ['strange', 'weird', 'magical', 'amazing', 'bizarre'];

// renders as one plain sentence — the whole line is measured up front and pinned to a
// fixed width (the widest of all word variants), so nothing shifts or gets extra padding
// as the word swaps; the text itself flows normally with ordinary single-space gaps.
//
// The single-line box only fits on wide-enough viewports. Below that, we don't let the
// browser's natural text-wrap decide where to break — that reintroduces the exact bug this
// is designed to avoid: the reserved box would have to shrink to fit the container, at which
// point it's no longer guaranteed to fit the WIDEST word, so short words fit on one line while
// long ones spill an "extra" line — different words rendering at different heights and the
// footer moving under them. Instead we explicitly pick one of two fixed layouts up front —
// single-line or two-line (prefix, then a fixed-width word row) — based on the worst case
// (the widest word), so every word behaves identically in whichever mode is active.
const FooterHeadline = () => {
  const [displayText, setDisplayText] = useState(STRANGE_WORDS[0]);
  const [lineWidth, setLineWidth] = useState(0);
  const [wordWidth, setWordWidth] = useState(0);
  const [stacked, setStacked] = useState(false);
  const wrapRef = useRef(null);
  const measureRefs = useRef([]);
  const wordMeasureRefs = useRef([]);

  // measure every word variant with the exact same markup/CSS as the live version (off-screen),
  // so the reserved width is exact — no font-metric guessing that could over/undershoot
  useLayoutEffect(() => {
    const measure = () => {
      if (!wrapRef.current) return;
      const fullWidths = measureRefs.current.map((el) => (el ? el.getBoundingClientRect().width : 0));
      const wordWidths = wordMeasureRefs.current.map((el) => (el ? el.getBoundingClientRect().width : 0));
      const fullIdeal = Math.ceil(Math.max(0, ...fullWidths)) + 1;
      const wordIdeal = Math.ceil(Math.max(0, ...wordWidths)) + 1;
      const available = wrapRef.current.parentElement.clientWidth;
      // guard against a premature read (fonts/layout not settled yet): even the shortest
      // variant at the smallest font size in the clamp() is always well over 100px wide, so
      // anything under that is bogus — skip committing it rather than locking in a tiny box
      // that nowrap then renders as visibly overflowing text
      if (fullIdeal < 100 || wordIdeal < 20) return;
      setLineWidth(fullIdeal);
      setWordWidth(wordIdeal);
      setStacked(fullIdeal > available);
    };
    measure();
    // the display font loads async (webfont parse, even from a data URI) — if it swaps in
    // after this first pass, re-measure so the reserved width reflects its real glyph widths
    if (document.fonts && document.fonts.ready) document.fonts.ready.then(measure);
    // belt-and-suspenders: the very first measure can occasionally read back a near-zero
    // width if layout/fonts haven't fully settled yet on mount — with nowrap now in play, an
    // under-measured box means the text visibly overflows instead of just wrapping, so this
    // needs to be caught for sure — several staggered follow-up passes after paint
    const raf1 = requestAnimationFrame(() => requestAnimationFrame(measure));
    const timeouts = [100, 300, 600, 1200, 2000].map((ms) => setTimeout(measure, ms));
    window.addEventListener('resize', measure);
    return () => {
      window.removeEventListener('resize', measure);
      cancelAnimationFrame(raf1);
      timeouts.forEach(clearTimeout);
    };
  }, []);

  // typewriter transition: hold the full word, backspace it out, pause, then type the next
  // one in — instead of a clean cross-fade swap
  useEffect(() => {
    let timeoutId;
    let cancelled = false;
    let idx = 0;
    let text = STRANGE_WORDS[0];

    const HOLD_MS = () => 5500 + Math.random() * 3500; // stays on screen longer than before
    const DELETE_MS = 55;
    const TYPE_MS = 75;

    function holdThenDelete() {
      timeoutId = setTimeout(deleteStep, HOLD_MS());
    }
    function deleteStep() {
      if (cancelled) return;
      text = text.slice(0, -1);
      setDisplayText(text);
      if (text.length > 0) {
        timeoutId = setTimeout(deleteStep, DELETE_MS);
      } else {
        idx = (idx + 1) % STRANGE_WORDS.length;
        timeoutId = setTimeout(() => typeStep(STRANGE_WORDS[idx], 0), 320);
      }
    }
    function typeStep(word, pos) {
      if (cancelled) return;
      text = word.slice(0, pos + 1);
      setDisplayText(text);
      if (pos + 1 < word.length) {
        timeoutId = setTimeout(() => typeStep(word, pos + 1), TYPE_MS);
      } else {
        holdThenDelete();
      }
    }
    holdThenDelete();
    return () => { cancelled = true; clearTimeout(timeoutId); };
  }, []);

  measureRefs.current = [];
  wordMeasureRefs.current = [];

  const wordEl = (
    <em style={{ display: 'inline-block' }}>
      {displayText}<span className="caret" aria-hidden="true" />
    </em>
  );

  return (
    <h2>
      {stacked ? (
        <>
          <span style={{ display: 'block' }}>Let&rsquo;s build something</span>
          <span style={{ display: 'inline-block', width: wordWidth || undefined, textAlign: 'center', whiteSpace: 'nowrap' }}>
            {wordEl}.
          </span>
        </>
      ) : (
        <span ref={wrapRef} style={{ display: 'inline-block', width: lineWidth || undefined, textAlign: 'left', whiteSpace: 'nowrap' }}>
          Let&rsquo;s build something{' '}
          {wordEl}.
        </span>
      )}
      {/* off-screen reference for the single-line box: only needed to establish wrapRef when
          not stacked, so keep a hidden anchor around even in stacked mode */}
      {stacked && <span ref={wrapRef} style={{ position: 'absolute', visibility: 'hidden', width: 0, height: 0 }} />}
      <span aria-hidden="true" style={{ position: 'absolute', visibility: 'hidden', pointerEvents: 'none', left: -99999, top: 0 }}>
        {STRANGE_WORDS.map((w) => (
          <span key={w} ref={(el) => measureRefs.current.push(el)} style={{ display: 'block', whiteSpace: 'nowrap' }}>
            Let&rsquo;s build something <em>{w}</em>.
          </span>
        ))}
        {STRANGE_WORDS.map((w) => (
          <span key={'word-' + w} ref={(el) => wordMeasureRefs.current.push(el)} style={{ display: 'block', whiteSpace: 'nowrap' }}>
            <em>{w}</em>.
          </span>
        ))}
      </span>
    </h2>
  );
};

