import styled, { keyframes, createGlobalStyle } from 'styled-components';

// ── Phosphor palette (mirrors the real Homunculus CRT skin) ──────────────────
export const C = {
  bg: '#050806',
  bgElev: '#0a0f0b',
  green: '#4dff9b',
  greenSoft: '#9dffca',
  greenDim: '#2f7a54',
  crimson: '#ff2d55',
  amber: '#ffb347',
  blue: '#5ac8fa',
  border: 'rgba(77, 255, 155, 0.18)',
  borderStrong: 'rgba(77, 255, 155, 0.45)',
};

// Faint moving scanline + flicker to sell the CRT feel, scoped to this page.
export const CrtGlobal = createGlobalStyle`
  @keyframes hmnScan {
    0% { background-position: 0 0; }
    100% { background-position: 0 100vh; }
  }
`;

const flicker = keyframes`
  0%, 96%, 100% { opacity: 1; }
  97% { opacity: 0.82; }
  98% { opacity: 0.95; }
`;

const bootIn = keyframes`
  from { opacity: 0; transform: translateY(14px); }
  to   { opacity: 1; transform: translateY(0); }
`;

const sweep = keyframes`
  0%   { transform: translateX(-120%); }
  100% { transform: translateX(120%); }
`;

export const Page = styled.div`
  /* Scanlines are baked into the page background (an extra gradient layer),
     not a separate position:fixed overlay — a fixed full-viewport layer can
     trigger black-screen compositing bugs in some Chromium builds. */
  background:
    repeating-linear-gradient(
      0deg,
      rgba(0,0,0,0) 0px,
      rgba(0,0,0,0) 2px,
      rgba(0,0,0,0.16) 3px,
      rgba(0,0,0,0) 4px
    ),
    radial-gradient(ellipse at 50% -10%, rgba(77,255,155,0.10), transparent 60%),
    ${C.bg};
  color: ${C.greenSoft};
  font-family: 'Share Tech Mono', 'Fira Code', ui-monospace, monospace;
  min-height: 100vh;
  position: relative;
  overflow-x: hidden;
`;

