// ── Feature grid ─────────────────────────────────────────────────────────────
export const Grid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
  gap: 16px;
`;

export const Card = styled.article`
  position: relative;
  background: linear-gradient(180deg, ${C.bgElev}, rgba(5,8,6,0.6));
  border: 0.5px solid ${C.border};
  padding: 22px 22px 24px;
  overflow: hidden;
  animation: ${bootIn} 0.5s ease both;
  transition: border-color 0.2s ease, transform 0.2s ease, box-shadow 0.2s ease;

  &:hover {
    border-color: ${C.borderStrong};
    transform: translateY(-3px);
    box-shadow: 0 10px 30px rgba(0,0,0,0.5), 0 0 0 0.5px ${C.borderStrong};
  }

  /* corner tick */
  &:after {
    content: '';
    position: absolute;
    top: 10px; right: 10px;
    width: 8px; height: 8px;
    border-top: 1px solid ${C.greenDim};
    border-right: 1px solid ${C.greenDim};
  }

  /* hover sweep */
  &:before {
    content: '';
    position: absolute;
    top: 0; left: 0;
    width: 40%; height: 100%;
    background: linear-gradient(90deg, transparent, rgba(77,255,155,0.06), transparent);
    transform: translateX(-120%);
    pointer-events: none;
  }
  &:hover:before { animation: ${sweep} 0.9s ease; }
`;

