    // three independent reasons to pause: tab backgrounded, the hero scrolled off screen, or a
    // modal (résumé/contact) is open over the page — combine them so any one holds the pause
    let offscreen = false, hidden = document.hidden, modalOpen = false;
    const applyPause = () => setPaused(offscreen || hidden || modalOpen);
    const io = 'IntersectionObserver' in window
